class CifarLoader:
    def __init__(self, path, train=True, batch_size=500, aug=None):
        from pathlib import Path

        data_path = Path(path) / ("train.pt" if train else "test.pt")
        if not data_path.exists():
            dset = torchvision.datasets.CIFAR10(path, download=True, train=train)
            images = torch.tensor(dset.data)
            labels = torch.tensor(dset.targets)
            torch.save({"images": images, "labels": labels, "classes": dset.classes}, data_path)

        data = torch.load(data_path, map_location=torch.device("cuda"), weights_only=False)
        self.images, self.labels, self.classes = data["images"], data["labels"], data["classes"]
        self.images = (self.images.permute(0, 3, 1, 2).contiguous().to(torch.float16).div_(255)).to(memory_format=torch.channels_last)

        mean = torch.tensor(CIFAR_MEAN, device=self.images.device, dtype=self.images.dtype).view(1, 3, 1, 1)
        std = torch.tensor(CIFAR_STD, device=self.images.device, dtype=self.images.dtype).view(1, 3, 1, 1)
        self.normalized_images = self.images.sub(mean).div(std)

        self.proc_images = {}
        self.epoch = 0
        self.aug = aug or {}
        for key in self.aug:
            if key not in {"flip", "translate"}:
                raise ValueError(f"Unrecognized augmentation key: {key}")
        self.batch_size = batch_size
        self.drop_last = train
        self.shuffle = train

        if self.aug.get("flip", False):
            self.proc_images["flip"] = self.normalized_images.flip(-1)
        pad = self.aug.get("translate", 0)
        if pad > 0:
            self.proc_images["pad"] = F.pad(self.normalized_images, (pad,) * 4, "reflect")
            if self.aug.get("flip", False):
                self.proc_images["pad_flip"] = F.pad(self.proc_images["flip"], (pad,) * 4, "reflect")

    def normalize(self, x):
        mean = torch.tensor(CIFAR_MEAN, device=x.device, dtype=x.dtype).view(1, 3, 1, 1)
        std = torch.tensor(CIFAR_STD, device=x.device, dtype=x.dtype).view(1, 3, 1, 1)
        return x.sub(mean).div(std)

    def __len__(self):
        if self.drop_last:
            return len(self.images) // self.batch_size
        return ceil(len(self.images) / self.batch_size)

    def __iter__(self):
        use_flip = self.aug.get("flip", False) and (self.epoch % 2 == 1)
        pad = self.aug.get("translate", 0)
        base_images = self.proc_images["flip"] if use_flip and self.aug.get("flip", False) else self.normalized_images
        padded_images = None
        if pad > 0:
            padded_images = self.proc_images["pad_flip"] if use_flip and self.aug.get("flip", False) else self.proc_images["pad"]

        self.epoch += 1
        indices = (torch.randperm if self.shuffle else torch.arange)(len(base_images), device=base_images.device)
        for i in range(len(self)):
            idxs = indices[i * self.batch_size : (i + 1) * self.batch_size]
            if pad > 0:
                x = torch.randint(0, 2 * pad + 1, (1,), device=idxs.device).item()
                y = torch.randint(0, 2 * pad + 1, (1,), device=idxs.device).item()
                yield padded_images[idxs, :, y : y + self.images.shape[-2], x : x + self.images.shape[-1]], self.labels[idxs]
            else:
                yield base_images[idxs], self.labels[idxs]
